import{_ as d,o as a,c as r,a4 as o}from"./chunks/framework.ChErgFjV.js";const c=JSON.parse('{"title":"第二章 初中数学知识","description":"","frontmatter":{"title":"第二章 初中数学知识","date":"2026-07-08T00:00:00.000Z","tags":["教师资格考试","数学学科知识","初中数学"]},"headers":[],"relativePath":"study/teacher-cert/math-subject/chapter2.md","filePath":"study/teacher-cert/math-subject/chapter2.md","lastUpdated":null}'),e={name:"study/teacher-cert/math-subject/chapter2.md"};function h(l,t,n,b,s,i){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="第二章-初中数学知识" tabindex="-1">第二章 初中数学知识 <a class="header-anchor" href="#第二章-初中数学知识" aria-label="Permalink to &quot;第二章 初中数学知识&quot;">​</a></h1><blockquote><p>本章考情：选择题+简答题，约 15-20 分 重点：函数、几何证明、概率统计 详见 <a href="/my-knowledge/study/junior-math/">初中数学知识体系</a></p></blockquote><hr><h2 id="_2-1-数与代数-🔴🔴🔴" tabindex="-1">2.1 数与代数 🔴🔴🔴 <a class="header-anchor" href="#_2-1-数与代数-🔴🔴🔴" aria-label="Permalink to &quot;2.1 数与代数 🔴🔴🔴&quot;">​</a></h2><h3 id="实数-🔴" tabindex="-1">实数 🔴 <a class="header-anchor" href="#实数-🔴" aria-label="Permalink to &quot;实数 🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>概念</th><th>要点</th><th>易错点</th></tr></thead><tbody><tr><td>有理数</td><td>整数+分数（有限小数或无限循环小数）</td><td>π 不是有理数</td></tr><tr><td>无理数</td><td>无限不循环小数</td><td>√2、π、e</td></tr><tr><td>绝对值 🔴</td><td>|a| = a(a≥0) 或 -a(a&lt;0)</td><td>分类讨论</td></tr><tr><td>科学记数法</td><td>a×10^n（1≤|a|&lt;10）</td><td>n 的正负</td></tr></tbody></table><h3 id="代数式-🔴🔴" tabindex="-1">代数式 🔴🔴 <a class="header-anchor" href="#代数式-🔴🔴" aria-label="Permalink to &quot;代数式 🔴🔴&quot;">​</a></h3><p><strong>整式运算</strong>：</p><ul><li>幂的运算：a^m · a^n = a^(m+n)；(a^m)^n = a^(mn)；(ab)^n = a^n·b^n</li><li>乘法公式 🔴🔴： <ul><li>(a+b)(a-b) = a²-b²（平方差）</li><li>(a±b)² = a²±2ab+b²（完全平方）</li></ul></li></ul><p><strong>因式分解</strong> 🔴🔴：</p><ol><li>提取公因式法</li><li>公式法（平方差/完全平方）</li><li>十字相乘法</li></ol><p><strong>分式</strong> 🔴：</p><ul><li>分式有意义的条件：分母≠0</li><li>分式基本性质：分子分母同乘/除非零数，值不变</li></ul><h3 id="方程与不等式-🔴🔴🔴" tabindex="-1">方程与不等式 🔴🔴🔴 <a class="header-anchor" href="#方程与不等式-🔴🔴🔴" aria-label="Permalink to &quot;方程与不等式 🔴🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>一般形式</th><th>解法</th><th>重难点</th></tr></thead><tbody><tr><td>一元一次方程</td><td>ax+b=0</td><td>移项</td><td>应用题建模 🔴</td></tr><tr><td>二元一次方程组</td><td>{a₁x+b₁y=c₁; a₂x+b₂y=c₂}</td><td>代入/加减消元</td><td>实际问题</td></tr><tr><td>一元二次方程 🔴🔴</td><td>ax²+bx+c=0</td><td>因式分解/公式法</td><td>根的判别式 Δ=b²-4ac 🔴🔴</td></tr><tr><td>分式方程</td><td>—</td><td>去分母→解整式方程→验根 🔴</td><td>增根问题 🔴</td></tr><tr><td>一元一次不等式</td><td>ax+b&gt;0</td><td>类似解方程（注意变号）</td><td>不等号方向</td></tr></tbody></table><p><strong>一元二次方程根的判别式</strong> 🔴🔴🔴：</p><ul><li>Δ&gt;0 ⇒ 两个不相等实根</li><li>Δ=0 ⇒ 两个相等实根</li><li>Δ&lt;0 ⇒ 无实根</li></ul><p><strong>韦达定理</strong> 🔴🔴：x₁+x₂=-b/a，x₁·x₂=c/a</p><h3 id="函数-🔴🔴🔴" tabindex="-1">函数 🔴🔴🔴 <a class="header-anchor" href="#函数-🔴🔴🔴" aria-label="Permalink to &quot;函数 🔴🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>函数</th><th>解析式</th><th>图像特征</th><th>关键性质</th></tr></thead><tbody><tr><td>一次函数 🔴🔴</td><td>y=kx+b</td><td>直线</td><td>k&gt;0 递增，k&lt;0 递减</td></tr><tr><td>反比例函数</td><td>y=k/x</td><td>双曲线</td><td>k&gt;0 一三象限，k&lt;0 二四象限</td></tr><tr><td>二次函数 🔴🔴🔴</td><td>y=ax²+bx+c</td><td>抛物线</td><td>顶点(-b/2a, (4ac-b²)/4a)，a&gt;0 开口向上</td></tr></tbody></table><p><strong>二次函数三种形式</strong> 🔴🔴🔴：</p><ol><li>一般式：y=ax²+bx+c</li><li>顶点式：y=a(x-h)²+k（顶点(h,k)）</li><li>交点式：y=a(x-x₁)(x-x₂)（与 x 轴交于 x₁,x₂）</li></ol><hr><h2 id="_2-2-图形与几何-🔴🔴🔴" tabindex="-1">2.2 图形与几何 🔴🔴🔴 <a class="header-anchor" href="#_2-2-图形与几何-🔴🔴🔴" aria-label="Permalink to &quot;2.2 图形与几何 🔴🔴🔴&quot;">​</a></h2><h3 id="三角形-🔴🔴🔴" tabindex="-1">三角形 🔴🔴🔴 <a class="header-anchor" href="#三角形-🔴🔴🔴" aria-label="Permalink to &quot;三角形 🔴🔴🔴&quot;">​</a></h3><p><strong>全等三角形判定</strong> 🔴🔴🔴：SSS、SAS、ASA、AAS、HL（直角三角形）</p><p><strong>相似三角形判定</strong> 🔴🔴🔴：AA、SAS（边成比例+夹角相等）、SSS（三边成比例）</p><p><strong>特殊三角形</strong> 🔴：</p><table tabindex="0"><thead><tr><th>类型</th><th>性质</th><th>判定</th></tr></thead><tbody><tr><td>等腰三角形</td><td>两腰相等，底角相等</td><td>等角对等边</td></tr><tr><td>等边三角形</td><td>三边相等，三角均60°</td><td>三边相等/三角相等</td></tr><tr><td>直角三角形 🔴</td><td>勾股定理 a²+b²=c²</td><td>一个角为90°</td></tr></tbody></table><p><strong>三角形面积</strong>：S = ½ah = ½ab·sinC</p><h3 id="四边形-🔴🔴" tabindex="-1">四边形 🔴🔴 <a class="header-anchor" href="#四边形-🔴🔴" aria-label="Permalink to &quot;四边形 🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>图形</th><th>性质</th><th>判定</th></tr></thead><tbody><tr><td>平行四边形 🔴</td><td>对边平行且相等、对角相等、对角线互相平分</td><td>定义/两组对边相等/对角线互相平分</td></tr><tr><td>矩形</td><td>平行四边形+直角</td><td>有一个直角的平行四边形/对角线相等</td></tr><tr><td>菱形</td><td>平行四边形+四边相等</td><td>有一组邻边相等的平行四边形/对角线垂直</td></tr><tr><td>正方形</td><td>矩形+菱形</td><td>既是矩形又是菱形</td></tr><tr><td>梯形</td><td>只有一组对边平行</td><td>定义</td></tr></tbody></table><p><strong>四边形关系</strong> 🔴🔴：平行四边形 → 矩形/菱形 → 正方形</p><h3 id="圆-🔴🔴🔴" tabindex="-1">圆 🔴🔴🔴 <a class="header-anchor" href="#圆-🔴🔴🔴" aria-label="Permalink to &quot;圆 🔴🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>知识点</th><th>公式/性质</th></tr></thead><tbody><tr><td>周长</td><td>C = 2πr</td></tr><tr><td>面积</td><td>S = πr²</td></tr><tr><td>弧长 🔴</td><td>l = nπr/180</td></tr><tr><td>扇形面积 🔴</td><td>S = nπr²/360 = ½lr</td></tr><tr><td>圆周角定理 🔴🔴</td><td>同弧上的圆周角 = 圆心角的一半</td></tr><tr><td>切线性质 🔴🔴</td><td>切线⊥半径（过切点）</td></tr><tr><td>切线长定理</td><td>从圆外一点到圆的两条切线长相等</td></tr></tbody></table><h3 id="锐角三角函数-🔴🔴" tabindex="-1">锐角三角函数 🔴🔴 <a class="header-anchor" href="#锐角三角函数-🔴🔴" aria-label="Permalink to &quot;锐角三角函数 🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>函数</th><th>定义</th><th>特殊角值（30°/45°/60°）</th></tr></thead><tbody><tr><td>sinA 🔴</td><td>对边/斜边</td><td>1/2, √2/2, √3/2</td></tr><tr><td>cosA</td><td>邻边/斜边</td><td>√3/2, √2/2, 1/2</td></tr><tr><td>tanA</td><td>对边/邻边</td><td>√3/3, 1, √3</td></tr></tbody></table><p><strong>解直角三角形</strong> 🔴🔴：已知两个元素（至少一个边），可求其余元素</p><hr><h2 id="_2-3-统计与概率-🔴🔴" tabindex="-1">2.3 统计与概率 🔴🔴 <a class="header-anchor" href="#_2-3-统计与概率-🔴🔴" aria-label="Permalink to &quot;2.3 统计与概率 🔴🔴&quot;">​</a></h2><h3 id="统计-🔴" tabindex="-1">统计 🔴 <a class="header-anchor" href="#统计-🔴" aria-label="Permalink to &quot;统计 🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>统计量</th><th>定义</th><th>特点</th></tr></thead><tbody><tr><td>平均数 🔴</td><td>&amp;bar;x = (∑x_i)/n</td><td>受极端值影响</td></tr><tr><td>中位数</td><td>排序后中间值</td><td>不受极端值影响</td></tr><tr><td>众数</td><td>出现次数最多的值</td><td>可能有多个</td></tr><tr><td>方差 🔴</td><td>s² = ∑(x_i-&amp;bar;x)²/n</td><td>越小越稳定</td></tr></tbody></table><p><strong>调查方式</strong> 🔴：</p><ul><li>全面调查（普查）— 精确但费时</li><li>抽样调查 — 省时但有误差</li></ul><p><strong>抽样原则</strong>：随机性、代表性</p><h3 id="概率-🔴🔴" tabindex="-1">概率 🔴🔴 <a class="header-anchor" href="#概率-🔴🔴" aria-label="Permalink to &quot;概率 🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>概念</th><th>含义</th></tr></thead><tbody><tr><td>随机事件</td><td>可能发生也可能不发生</td></tr><tr><td>必然事件</td><td>P=1</td></tr><tr><td>不可能事件</td><td>P=0</td></tr><tr><td>概率 🔴</td><td>P(A) = 事件A包含的结果数/总结果数</td></tr></tbody></table><p><strong>树状图/列表法</strong> 🔴🔴 — 列举所有等可能结果</p><hr><h2 id="近三年真题精选" tabindex="-1">近三年真题精选 <a class="header-anchor" href="#近三年真题精选" aria-label="Permalink to &quot;近三年真题精选&quot;">​</a></h2><p><strong>1.</strong>（2024上）下列各数中，属于无理数的是（ ）</p><p>A. √4   B. 0.3̅   C. √3   D. 22/7</p><blockquote><p><strong>答案</strong>：C   √4=2 有理数，0.3̅ 循环小数有理数，√3 无理数</p></blockquote><p><strong>2.</strong>（2024上）方程 x²-5x+6=0 的两个根分别为（ ）</p><p>A. 1和6   B. -1和-6   C. 2和3   D. -2和-3</p><blockquote><p><strong>答案</strong>：C   (x-2)(x-3)=0</p></blockquote><p><strong>3.</strong>（2023下）二次函数 y=x²-4x+3 的顶点坐标为（ ）</p><p>A. (2,1)   B. (2,-1)   C. (-2,1)   D. (-2,-1)</p><blockquote><p><strong>答案</strong>：B   x=-b/2a=4/2=2，y=4-8+3=-1，顶点(2,-1)</p></blockquote><p><strong>4.</strong>（2023上）在▵ABC中，∠C=90°，AC=3，BC=4，则 sinA=（ ）</p><p>A. 3/5   B. 4/5   C. 3/4   D. 4/3</p><blockquote><p><strong>答案</strong>：B   AB=5，sinA=BC/AB=4/5</p></blockquote><p><strong>5.</strong>（2023上）一组数据 2,3,5,5,5 的众数和中位数分别为（ ）</p><p>A. 5和5   B. 5和4   C. 5和3   D. 3和5</p><blockquote><p><strong>答案</strong>：A   众数=5（出现3次），排序后中位数=5</p></blockquote><p><strong>6.</strong>（2024上）分解因式：x³-x</p><blockquote><p><strong>解</strong>：x³-x = x(x²-1) = x(x+1)(x-1)</p></blockquote><p><strong>7.</strong>（2023下）已知抛物线 y=ax²+bx+c 经过点(0,3)，顶点为(1,4)，求解析式。</p><blockquote><p><strong>解</strong>：设顶点式 y=a(x-1)²+4 过(0,3)：a(0-1)²+4=3 ⇒ a+4=3 ⇒ a=-1 y=-(x-1)²+4 = -x²+2x+3</p></blockquote><p><strong>8.</strong>（2024上）如图，圆O的半径为5，弦AB=8，求圆心O到AB的距离。</p><blockquote><p><strong>解</strong>：过O作OC⊥AB于C，则AC=BC=4 OC = √(OA²-AC²) = √(25-16) = 3</p></blockquote><p><strong>9.</strong>（2023下）简述&quot;勾股定理&quot;的内容及其在初中数学中的教学价值。</p><blockquote><p><strong>答</strong>：勾股定理：直角三角形中，两直角边的平方和等于斜边的平方，即 a²+b²=c²。 教学价值：①是几何学中最基本最重要的定理之一；②体现了数形结合思想；③是联系代数与几何的桥梁；④在测量、工程等领域有广泛应用；⑤是培养学生逻辑推理能力的重要载体。</p></blockquote><p><strong>10.</strong>（2023上）某校对100名学生进行&quot;最喜欢的课外活动&quot;调查，结果如下表。请用扇形统计图表示，并计算各扇形的圆心角度数。</p><table tabindex="0"><thead><tr><th>活动</th><th>体育</th><th>阅读</th><th>音乐</th><th>其他</th></tr></thead><tbody><tr><td>人数</td><td>40</td><td>25</td><td>20</td><td>15</td></tr></tbody></table><blockquote><p><strong>解</strong>： 体育：40/100×360°=144° 阅读：25/100×360°=90° 音乐：20/100×360°=72° 其他：15/100×360°=54°</p></blockquote>',76)])])}const u=d(e,[["render",h]]);export{c as __pageData,u as default};
